      //MARK: WHERE RULES (ENTITY)
      public static func WHERE_wr1(SELF: eADDRESS.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }

        let _TEMP1 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.INTERNAL_LOCATION )
        let _TEMP2 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.STREET_NUMBER )
        let _TEMP3 /* SDAI.LOGICAL */ = _TEMP1 || _TEMP2
        let _TEMP4 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.STREET )
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP3 || _TEMP4
        let _TEMP6 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.POSTAL_BOX )
        let _TEMP7 /* SDAI.LOGICAL */ = _TEMP5 || _TEMP6
        let _TEMP8 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.TOWN )
        let _TEMP9 /* SDAI.LOGICAL */ = _TEMP7 || _TEMP8
        let _TEMP10 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.REGION )
        let _TEMP11 /* SDAI.LOGICAL */ = _TEMP9 || _TEMP10
        let _TEMP12 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.POSTAL_CODE )
        let _TEMP13 /* SDAI.LOGICAL */ = _TEMP11 || _TEMP12
        let _TEMP14 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.COUNTRY )
        let _TEMP15 /* SDAI.LOGICAL */ = _TEMP13 || _TEMP14
        let _TEMP16 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.FACSIMILE_NUMBER )
        let _TEMP17 /* SDAI.LOGICAL */ = _TEMP15 || _TEMP16
        let _TEMP18 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.TELEPHONE_NUMBER )
        let _TEMP19 /* SDAI.LOGICAL */ = _TEMP17 || _TEMP18
        let _TEMP20 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.ELECTRONIC_MAIL_ADDRESS )
        let _TEMP21 /* SDAI.LOGICAL */ = _TEMP19 || _TEMP20
        let _TEMP22 /* SDAI.BOOLEAN */ = SDAI.EXISTS( SELF.TELEX_NUMBER )
        let _TEMP23 /* SDAI.LOGICAL */ = _TEMP21 || _TEMP22
        return _TEMP23
      }

